async function fetchLink(e,t=null){try{const n=await fetch(`${window.location.origin}/api/pull`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({slug:e,user_key:t})}),o=await n.json();if(!n.ok)throw new Error(o.error||"Failed to fetch or decrypt");window.location.replace(o.response)}catch(e){console.error("Frontend Fetch Error:",e.message),document.querySelector(".redirected").textContent="This link is unavailable.",document.querySelector(".anew").classList.add("right")}}(function(){const e=window.location.pathname.replace("/","");e.match(/[^0-9a-zA-Z]/)?(console.error("Frontend Fetch Error:","Invalid link."),document.querySelector(".redirected").textContent="This link is invalid.",document.querySelector(".anew").classList.add("right")):fetchLink(e,null)})();